import type { CurriculumModule, Lesson } from '@/lib/types'

const ol5Lessons: Lesson[] = [
  {
    id: 'ol5-l1', moduleId: 'ol5-econometrics', title: 'Data, Variables, and Descriptive Statistics Review', description: 'Distinguish cross-section, time-series, and panel data; review mean, variance, standard deviation, and covariance with economic applications.', order: 1, estimatedMinutes: 35, tags: ['olympiad', 'econometrics', 'data', 'statistics'],
    flashcards: [
      { id: 'fc-ol5-l1-1', front: 'Distinguish cross-sectional, time-series, and panel data.', back: 'Cross-sectional data observe many units (individuals, firms, countries) at a single point in time. Time-series data track one unit across many time periods. Panel (longitudinal) data combine both: multiple units observed over multiple periods, enabling control for unobserved unit-level heterogeneity.', tags: ['olympiad', 'econometrics', 'data'] },
      { id: 'fc-ol5-l1-2', front: 'What is the covariance and what does its sign indicate?', back: 'Cov(X,Y) = E[(X − μX)(Y − μY)]. A positive covariance means X and Y tend to move in the same direction; negative means they move in opposite directions. Covariance is scale-dependent, so the correlation coefficient ρ = Cov(X,Y)/(σX·σY) is preferred for comparisons across different datasets.', tags: ['olympiad', 'statistics', 'covariance'] },
      { id: 'fc-ol5-l1-3', front: 'Why is variance a better measure of dispersion than the mean absolute deviation for econometric work?', back: 'Variance (σ² = E[(X−μ)²]) is differentiable everywhere, making it tractable in optimisation (e.g., OLS minimises a sum of squared residuals). It also links naturally to the normal distribution and gives rise to the standard error of estimators. Mean absolute deviation is non-differentiable at zero and harder to work with algebraically.', tags: ['olympiad', 'statistics', 'variance'] },
    ],
    quiz: [
      { id: 'q-ol5-l1-1', type: 'mcq', question: 'A researcher collects GDP, investment, and consumption data for 50 countries over 30 years. What type of data structure does this represent?', options: ['Panel data', 'Cross-sectional data', 'Time-series data', 'Experimental data'], correctAnswer: 0, explanation: 'Panel data (also called longitudinal data) track multiple units — here, 50 countries — across multiple time periods — here, 30 years. Cross-sectional data would be one year only; time-series data would be one country only.', marks: 2, difficulty: 'olympiad' },
      { id: 'q-ol5-l1-2', type: 'mcq', question: 'The sample variance of a dataset with n observations is calculated by dividing the sum of squared deviations by (n−1) rather than n. This correction is called:', options: ['Bessel\'s correction', 'Gauss\'s adjustment', 'Jensen\'s inequality', 'Chebyshev\'s rule'], correctAnswer: 0, explanation: 'Bessel\'s correction (dividing by n−1 rather than n) produces an unbiased estimator of the population variance. Dividing by n gives the MLE of the variance but is biased downward in finite samples because the sample mean is used in place of the true (unknown) population mean.', marks: 2, difficulty: 'olympiad' },
    ],
    content: { isStub: true, conceptualExplanation: `Empirical economics begins with data, and understanding data structure is prerequisite to choosing an appropriate estimator. Cross-sectional datasets — a household survey conducted in a single year, or a snapshot of firm balance sheets — capture variation across units at a moment in time. These are rich in heterogeneity but cannot identify causal dynamics. Time-series datasets — quarterly GDP, monthly inflation, annual trade flows — capture how a single economy or market evolves, but are vulnerable to spurious correlations arising from shared trends. Panel datasets are the workhorse of modern empirical work: by stacking observations on N units over T periods they deliver both cross-sectional richness and longitudinal depth, while their structure enables powerful techniques — fixed effects, difference-in-differences — that eliminate confounding from time-invariant unit characteristics.\n\nDescriptive statistics summarise the location, spread, and co-movement of variables before any modelling begins. The mean μ is the first moment, measuring central tendency. The variance σ² is the second central moment, capturing dispersion; its square root, the standard deviation σ, restores original units and is more interpretable. The covariance Cov(X,Y) measures how two variables co-move in absolute terms; the Pearson correlation coefficient ρ = Cov(X,Y)/(σX σY) normalises this to the interval [−1, 1], facilitating comparison across variables with different scales. For olympiad purposes, be prepared to calculate these statistics from raw data, to interpret them in economic contexts (e.g., the covariance between education and wages, or between interest rates and investment), and to explain why the correlation coefficient is preferred to raw covariance when comparing relationships across datasets.`, prerequisiteRecap: `The welfare economics and externality module established that the optimal Pigouvian tax t* = EMC(Q*) aligns private and social marginal costs, while the Coase theorem shows that private bargaining achieves efficiency under zero transaction costs; cap-and-trade achieves cost-effectiveness by equalising firms' marginal abatement costs at the equilibrium permit price. Econometrics now provides the quantitative toolkit for measuring these welfare effects and identifying causal policy impacts from observational data.`, recallQuestions: [{ id: 'ol5-l1-recall-1', type: 'mcq' as const, question: 'A factory has private marginal cost PMC(Q) = 5 + Q and imposes external marginal cost EMC(Q) = 0.5Q on nearby residents. The market price is P = 35. A Pigouvian tax t* is set at the socially optimal output Q*. What is Q* and t*?', options: ['Q* = 20 and t* = 10, derived by solving P = PMC + EMC: 35 = 5 + Q + 0.5Q = 5 + 1.5Q → Q* = 20, then t* = EMC(20) = 0.5×20 = 10', 'Q* = 30 and t* = 15, derived by setting P = PMC only and then computing EMC at that output', 'Q* = 20 and t* = 5, equal to the slope of the EMC curve regardless of Q*', 'Q* = 25 and t* = 0, because the Coase theorem predicts that private bargaining achieves Q* without any tax'], correctAnswer: 0, explanation: 'Social optimum: P = SMC = PMC + EMC → 35 = (5+Q) + 0.5Q = 5 + 1.5Q → 1.5Q = 30 → Q* = 20. Pigouvian tax: t* = EMC(Q*) = 0.5 × 20 = 10. Verification: a firm facing PMC + t* = 5 + Q + 10 sets this equal to P = 35 → Q = 20 = Q*. The tax raises effective private marginal cost to equal social marginal cost at Q*, eliminating the deadweight loss triangle between Q* and the unregulated equilibrium.', marks: 1, difficulty: 'olympiad' as const }], realWorldHook: '', vocabulary: [], deeperDive: '', commonMisconceptions: [], examinerTip: '', didYouKnow: '' },
  },
  {
    id: 'ol5-l2', moduleId: 'ol5-econometrics', title: 'Ordinary Least Squares — Intuition and Mechanics', description: 'Explain OLS as minimising the sum of squared residuals; interpret slope and intercept coefficients; calculate R² and its meaning.', order: 2, estimatedMinutes: 50, tags: ['olympiad', 'OLS', 'regression', 'R-squared'],
    flashcards: [
      { id: 'fc-ol5-l2-1', front: 'What objective does OLS minimise, and what are the resulting normal equations?', back: 'OLS minimises Σ(Yi − β̂0 − β̂1Xi)² with respect to β̂0 and β̂1. Setting partial derivatives to zero yields the normal equations: β̂1 = Cov(X,Y)/Var(X) and β̂0 = Ȳ − β̂1·X̄. The estimated line always passes through the sample means (X̄, Ȳ).', tags: ['olympiad', 'OLS', 'regression'] },
      { id: 'fc-ol5-l2-2', front: 'How is R² defined and what does it measure?', back: 'R² = 1 − SSR/SST = ESS/SST, where SST = Σ(Yi−Ȳ)² (total variation), SSR = Σ(Yi−Ŷi)² (unexplained residual variation), and ESS = Σ(Ŷi−Ȳ)² (explained variation). R² ∈ [0,1] in simple OLS; it measures the proportion of the variance in Y explained by the model.', tags: ['olympiad', 'R-squared'] },
      { id: 'fc-ol5-l2-3', front: 'Interpret the OLS slope coefficient β̂1 in an earnings-education regression: log(wage) = β̂0 + β̂1·education + ε.', back: 'β̂1 is the estimated percentage change in wages for a one-unit (one year) increase in education, holding all other included factors constant. In a log-linear model, 100·β̂1 gives the approximate percent change. This captures the average partial effect of education in the sample, though without additional assumptions it need not identify a causal return to schooling.', tags: ['olympiad', 'OLS', 'interpretation'] },
    ],
    quiz: [
      { id: 'q-ol5-l2-1', type: 'mcq', question: 'In a simple OLS regression of Y on X, Cov(X,Y) = 12 and Var(X) = 4. What is the OLS slope estimate?', options: ['3', '48', '0.33', '8'], correctAnswer: 0, explanation: 'β̂1 = Cov(X,Y)/Var(X) = 12/4 = 3. This is the fundamental formula for the OLS slope in a bivariate regression, derived by minimising the sum of squared residuals.', marks: 2, difficulty: 'olympiad' },
      { id: 'q-ol5-l2-2', type: 'mcq', question: 'A regression of consumption on income gives R² = 0.85. Which statement is correct?', options: ['85% of the variance in consumption is explained by income', 'Income causes 85% of consumption', 'The regression has a 15% error rate', 'Adding more variables cannot raise R²'], correctAnswer: 0, explanation: 'R² = 0.85 means the model accounts for 85% of the total variation in consumption. It is a goodness-of-fit measure, not a statement of causation. Adding variables always weakly increases R², which is why adjusted R² is preferred for model comparison.', marks: 2, difficulty: 'olympiad' },
    ],
    content: { isStub: true, conceptualExplanation: `Ordinary Least Squares is the fundamental building block of empirical economics, and its geometric and algebraic logic is accessible to anyone comfortable with calculus and linear algebra. The problem OLS solves is: given a sample of (X, Y) pairs, find the linear function Ŷ = β̂0 + β̂1X that minimises the sum of squared vertical distances between actual data points and the fitted line. Squaring the residuals (rather than taking absolute values) penalises large deviations more heavily, ensures differentiability, and produces unique closed-form solutions. Taking derivatives of the objective function with respect to β̂0 and β̂1, setting them to zero, and solving yields β̂1 = Cov(X,Y)/Var(X) and β̂0 = Ȳ − β̂1X̄. These expressions make intuitive sense: the slope is the ratio of how much X and Y co-vary to how much X varies alone, and the intercept ensures the line passes through the sample means.\n\nR², the coefficient of determination, quantifies how well the fitted line tracks the actual data. It decomposes total variance (SST) into explained variance (ESS) and residual variance (SSR): SST = ESS + SSR, so R² = ESS/SST = 1 − SSR/SST. An R² of 0.80 means 80% of the sample variation in Y is associated with variation in X. However, R² has limitations that olympiad students must recognise: it rises mechanically whenever a variable is added, even an irrelevant one; it cannot diagnose whether the regression suffers from omitted variable bias or reverse causality; and a high R² is neither necessary nor sufficient for a well-specified model. Adjusted R² (which penalises for additional regressors) and out-of-sample prediction error are more informative diagnostics for model selection.`, prerequisiteRecap: `Descriptive statistics established that the covariance Cov(X,Y) = E[(X−μX)(Y−μY)] measures signed co-movement between two variables and that the Pearson correlation ρ = Cov(X,Y)/(σXσY) normalises this to [−1,1]; panel data structures — multiple units observed over multiple periods — provide the richest setting for econometric identification by combining cross-sectional and longitudinal variation. The OLS estimator now uses these statistical building blocks to find the minimum-sum-of-squared-residuals linear fit and decompose outcome variation into explained and unexplained components.`, recallQuestions: [{ id: 'ol5-l2-recall-1', type: 'mcq' as const, question: 'A researcher observes 50 countries over 30 years (a panel dataset). The sample covariance between trade openness X and GDP growth Y is Cov(X,Y) = 0.6, and Var(X) = 0.4. What is the OLS slope estimate β̂1, and what does it represent in a bivariate regression of Y on X?', options: ['β̂1 = Cov(X,Y)/Var(X) = 0.6/0.4 = 1.5; it estimates the average increase in GDP growth associated with a one-unit increase in trade openness, holding the sample variation in X fixed', 'β̂1 = Var(X)/Cov(X,Y) = 0.4/0.6 ≈ 0.67; the slope is the inverse of the covariance-to-variance ratio', 'β̂1 = Cov(X,Y) × Var(X) = 0.6 × 0.4 = 0.24; the slope is the product of co-movement and variance', 'β̂1 cannot be computed from a panel dataset using the bivariate OLS formula without first running a fixed effects transformation'], correctAnswer: 0, explanation: 'The OLS slope in a bivariate regression is β̂1 = Cov(X,Y)/Var(X) = 0.6/0.4 = 1.5. It estimates the average linear association: a one-unit increase in trade openness is associated with a 1.5-unit increase in GDP growth in the sample. Crucially, this is a sample estimate of an association, not a causal effect — endogeneity (reverse causality, omitted variables) means OLS may not recover the true causal parameter without additional identification strategies such as instrumental variables or fixed effects.', marks: 1, difficulty: 'olympiad' as const }], realWorldHook: '', vocabulary: [], deeperDive: '', commonMisconceptions: [], examinerTip: '', didYouKnow: '' },
  },
  {
    id: 'ol5-l3', moduleId: 'ol5-econometrics', title: 'OLS Assumptions and Violations', description: 'State the Gauss-Markov assumptions; explain what happens when each fails (heteroskedasticity, autocorrelation, multicollinearity); introduce remedies.', order: 3, estimatedMinutes: 50, tags: ['olympiad', 'Gauss-Markov', 'heteroskedasticity', 'autocorrelation'],
    flashcards: [
      { id: 'fc-ol5-l3-1', front: 'State the five Gauss-Markov assumptions and what they guarantee.', back: '(1) Linearity in parameters; (2) Random sampling; (3) No perfect multicollinearity; (4) Zero conditional mean of errors E[ε|X]=0 (exogeneity); (5) Homoskedasticity Var(ε|X)=σ². Under these, OLS is BLUE — the Best Linear Unbiased Estimator. Adding normality of errors yields exact inference via t- and F-distributions.', tags: ['olympiad', 'Gauss-Markov', 'OLS'] },
      { id: 'fc-ol5-l3-2', front: 'What is heteroskedasticity, what causes it, and how is it remedied?', back: 'Heteroskedasticity means Var(ε|X) is not constant — error variance changes with X (e.g., higher-income households have more variable expenditure). OLS remains unbiased but is no longer efficient and standard errors are incorrect. Remedy: use heteroskedasticity-robust (White) standard errors, or weighted least squares (WLS) if the variance structure is known.', tags: ['olympiad', 'heteroskedasticity'] },
      { id: 'fc-ol5-l3-3', front: 'What is autocorrelation, and why is it especially common in time-series regressions?', back: 'Autocorrelation (serial correlation) means Cov(εt, εt−k) ≠ 0 — today\'s error predicts future errors. Common in time series because macroeconomic shocks (recessions, policy changes) persist over time. OLS estimates are still unbiased but inefficient, and standard errors are understated. Remedies: Newey-West (HAC) standard errors, or GLS with an AR(1) error structure.', tags: ['olympiad', 'autocorrelation'] },
    ],
    quiz: [
      { id: 'q-ol5-l3-1', type: 'mcq', question: 'A researcher regresses firm R&D spending on firm size and finds that residuals are much larger for big firms than small ones. This is evidence of:', options: ['Heteroskedasticity', 'Multicollinearity', 'Autocorrelation', 'Perfect identification'], correctAnswer: 0, explanation: 'Heteroskedasticity is present when the variance of the residuals is not constant across observations. Here, larger firms have larger residuals — a classic pattern. The remedy is to use heteroskedasticity-robust standard errors rather than conventional OLS standard errors.', marks: 2, difficulty: 'olympiad' },
      { id: 'q-ol5-l3-2', type: 'mcq', question: 'Which Gauss-Markov assumption is violated when an omitted variable is correlated with both the outcome and a regressor?', options: ['Zero conditional mean (E[ε|X] = 0)', 'Homoskedasticity', 'No perfect multicollinearity', 'Linearity in parameters'], correctAnswer: 0, explanation: 'Omitted variable bias violates the zero conditional mean assumption. If the omitted variable is absorbed into ε and is correlated with an included X, then E[ε|X] ≠ 0, making OLS biased and inconsistent — not just inefficient.', marks: 2, difficulty: 'olympiad' },
    ],
    content: { isStub: true, conceptualExplanation: `The Gauss-Markov theorem establishes the optimality of OLS under five assumptions, and understanding what happens when each is violated is the core of applied econometrics. The most important assumption is the zero conditional mean: E[ε|X] = 0. This requires that the error term — which captures everything not included in the model — be on average unrelated to the regressors. When this holds, OLS is unbiased: on average across repeated samples it recovers the true coefficient. When it fails — due to omitted variables, reverse causality, or measurement error — OLS estimates are biased and inconsistent, meaning more data cannot fix the problem. This violation is fundamentally different from heteroskedasticity or autocorrelation, which cause inefficiency and incorrect standard errors but leave point estimates unbiased.\n\nHeteroskedasticity means the variance of the error term varies systematically with the regressors (e.g., residuals for large firms are more dispersed than for small ones). OLS point estimates remain unbiased, but the formula for standard errors assumes constant variance — so reported t-statistics and confidence intervals are invalid. The now-standard remedy is to use White's heteroskedasticity-robust standard errors, which adjust the variance-covariance matrix without any assumption about the error's variance structure. Autocorrelation, most problematic in time-series contexts, means that consecutive error terms are correlated — a positive shock today predicts a positive shock tomorrow. OLS standard errors understate uncertainty in this setting; Newey-West HAC (heteroskedasticity and autocorrelation consistent) standard errors are the remedy. Multicollinearity — near-linear relationships among regressors — inflates standard errors without biasing coefficients, making it harder to distinguish the individual effects of closely related variables.`, prerequisiteRecap: `The OLS estimator minimises the sum of squared residuals, yielding β̂1 = Cov(X,Y)/Var(X) and an R² = 1 − SSR/SST that measures the proportion of outcome variance explained by the model; the OLS line always passes through the sample means (X̄, Ȳ). The Gauss-Markov theorem now characterises the conditions under which OLS is the Best Linear Unbiased Estimator (BLUE), and identifies the distinct mechanisms — bias vs. inefficiency — by which different assumption violations compromise the estimator's properties.`, recallQuestions: [{ id: 'ol5-l3-recall-1', type: 'mcq' as const, question: 'A bivariate OLS regression of wages Y on education X gives R² = 0.40. A researcher then adds a second regressor, parental income Z, obtaining R² = 0.55. Which statement correctly interprets this change?', options: ['R² mechanically weakly increases when any regressor is added, regardless of whether it is truly relevant; the increase from 0.40 to 0.55 means parental income explains additional variance in wages, but adjusted R² should be examined to check whether this improvement exceeds what chance variation would produce', 'The increase from 0.40 to 0.55 proves that parental income causes wages to rise, since adding a causal variable always raises R²', 'R² can only increase if the new variable is not collinear with education, so this result implies parental income and education are perfectly uncorrelated', 'The change in R² from adding Z directly measures the omitted variable bias in the original education coefficient'], correctAnswer: 0, explanation: 'R² = 1 − SSR/SST never decreases when a regressor is added, because OLS can always set the new coefficient to zero and recover the original fit. The rise from 0.40 to 0.55 means parental income explains additional variation in wages, but this mechanical property means R² alone cannot confirm relevance or causality. Adjusted R² = 1 − (SSR/(n−k−1))/(SST/(n−1)) penalises for additional parameters and can fall if a regressor contributes less explanatory power than its degree-of-freedom cost.', marks: 1, difficulty: 'olympiad' as const }], realWorldHook: '', vocabulary: [], deeperDive: '', commonMisconceptions: [], examinerTip: '', didYouKnow: '' },
  },
  {
    id: 'ol5-l4', moduleId: 'ol5-econometrics', title: 'Hypothesis Testing in Econometrics', description: 'Define null and alternative hypotheses; conduct t-tests on coefficients; interpret p-values and confidence intervals in economic context.', order: 4, estimatedMinutes: 45, tags: ['olympiad', 't-test', 'p-value', 'confidence-intervals'],
    flashcards: [
      { id: 'fc-ol5-l4-1', front: 'How is the t-statistic for an OLS coefficient constructed?', back: 't = (β̂ − β0) / SE(β̂), where β0 is the hypothesised value (usually 0) and SE(β̂) is the estimated standard error of the coefficient. Under the null and Gauss-Markov assumptions (plus normality), this follows a t-distribution with n−k−1 degrees of freedom.', tags: ['olympiad', 't-test', 'hypothesis-testing'] },
      { id: 'fc-ol5-l4-2', front: 'What does a p-value of 0.03 mean in the context of a regression coefficient?', back: 'The p-value is the probability of observing a t-statistic at least as extreme as the one obtained, given that the null hypothesis (β = 0) is true. A p-value of 0.03 means there is a 3% chance of seeing this result by chance alone under H0. At a 5% significance level, we reject H0 and conclude the coefficient is statistically significant.', tags: ['olympiad', 'p-value'] },
      { id: 'fc-ol5-l4-3', front: 'Interpret a 95% confidence interval of [0.4, 1.2] for a wage-education slope coefficient.', back: 'In repeated sampling, 95% of such intervals would contain the true population parameter. We are 95% confident the true return to an additional year of education lies between 0.4 and 1.2 percentage points (in a log-wage specification). Since zero is excluded, the coefficient is significant at the 5% level — consistent with rejecting H0: β = 0.', tags: ['olympiad', 'confidence-intervals'] },
    ],
    quiz: [
      { id: 'q-ol5-l4-1', type: 'mcq', question: 'An OLS estimate of the interest rate effect on investment is β̂ = −2.4 with SE = 0.8. The t-statistic is −3.0. At a 1% significance level (critical value ≈ 2.58), you should:', options: ['Reject H0; the effect is statistically significant at 1%', 'Fail to reject H0; the effect is not significant', 'Reject H0; the effect is significant at 5% but not 1%', 'Accept H0; there is no relationship'], correctAnswer: 0, explanation: '|t| = 3.0 > 2.58, so we reject H0 at the 1% significance level and conclude the interest rate coefficient is significantly different from zero at conventional thresholds. Note: we never "accept" H0 — we only fail to reject it.', marks: 2, difficulty: 'olympiad' },
      { id: 'q-ol5-l4-2', type: 'mcq', question: 'A researcher runs 20 independent regressions and reports only the one with p < 0.05. This practice is best described as:', options: ['Publication bias / p-hacking', 'The multiple comparisons correction', 'Sequential hypothesis testing', 'Robust inference'], correctAnswer: 0, explanation: 'Selectively reporting results with p < 0.05 from many trials is called p-hacking or data dredging. With 20 independent tests at the 5% level, we expect on average one spurious rejection by chance alone. This is a major concern in replication crises across economics and social science.', marks: 2, difficulty: 'olympiad' },
    ],
    content: { isStub: true, conceptualExplanation: `Hypothesis testing in econometrics follows the classical Neyman-Pearson framework applied to regression coefficients. The null hypothesis H0 typically posits that a coefficient equals zero — that the corresponding variable has no linear effect on the outcome. The alternative H1 states the coefficient differs from zero (two-tailed) or has a specific sign (one-tailed). The test statistic is the t-ratio: (β̂ − 0)/SE(β̂), where SE(β̂) = √[σ̂²(X'X)⁻¹]. Under H0 and the Gauss-Markov assumptions plus normality, this ratio follows a t-distribution with n − k − 1 degrees of freedom (k regressors). As sample sizes grow large, t converges to standard normal, so the critical values 1.645 (10%), 1.96 (5%), and 2.576 (1%) become the relevant thresholds for two-tailed tests.\n\nThe p-value is often misunderstood, even by professional economists. It is the probability of observing a test statistic at least as extreme as the one computed, conditional on H0 being true — it is not the probability that H0 is true, nor the probability that results occurred by chance in the colloquial sense. A p-value of 0.03 means: if the null were true, only 3% of samples would produce an estimate this far from zero. This inverts the question most researchers want to ask (what is the probability that my theory is right?) but is what classical frequentist statistics delivers. Confidence intervals provide an equivalent and often more informative presentation: a 95% CI for β̂ of [a, b] means we reject any H0: β = β0 for any β0 outside [a, b] at the 5% level. Olympiad essays should present both the coefficient, its standard error, the t-statistic, and the confidence interval, and should discuss economic significance (is the magnitude large enough to matter?) separately from statistical significance.`, prerequisiteRecap: `The Gauss-Markov theorem established that OLS is BLUE — the Best Linear Unbiased Estimator — under the five classical assumptions, with the zero conditional mean E[ε|X] = 0 being the critical requirement for unbiasedness; violations such as heteroskedasticity (non-constant error variance) render OLS inefficient with incorrect standard errors, remediable by White's robust standard errors, while omitted variable bias violates E[ε|X] = 0 and causes inconsistency. Hypothesis testing now uses these standard errors to construct t-statistics and confidence intervals that formalise when observed coefficient estimates are distinguishable from zero.`, recallQuestions: [{ id: 'ol5-l4-recall-1', type: 'mcq' as const, question: 'A researcher estimates the effect of minimum wage on employment using OLS. The Gauss-Markov zero conditional mean assumption E[ε|X] = 0 is violated because local economic conditions affect both minimum wage levels and employment. What is the consequence for the OLS estimator?', options: ['The OLS estimator is biased and inconsistent — the minimum wage coefficient absorbs the effect of local economic conditions, and increasing the sample size does not remove this bias since the correlation between X and ε is structural', 'The OLS estimator is unbiased but inefficient — heteroskedasticity-robust standard errors can correct the problem', 'The OLS estimator is consistent but has inflated standard errors due to multicollinearity between minimum wage and economic conditions', 'The violation causes autocorrelation in the residuals, requiring Newey-West HAC standard errors as the remedy'], correctAnswer: 0, explanation: 'Violation of E[ε|X] = 0 — endogeneity — causes OLS to be biased and inconsistent. Local economic conditions are positively correlated with minimum wage (richer areas set higher minimums) and also affect employment directly; they are absorbed into ε, so Cov(X,ε) ≠ 0. OLS then conflates the causal effect of minimum wage with the effect of local prosperity, producing an upward-biased estimate. Unlike heteroskedasticity (which leaves estimates unbiased), endogeneity cannot be resolved by adjusting standard errors — an identification strategy such as instrumental variables or difference-in-differences is required.', marks: 1, difficulty: 'olympiad' as const }], realWorldHook: '', vocabulary: [], deeperDive: '', commonMisconceptions: [], examinerTip: '', didYouKnow: '' },
  },
  {
    id: 'ol5-l5', moduleId: 'ol5-econometrics', title: 'Multiple Regression and Model Specification', description: 'Extend OLS to multiple regressors; explain omitted variable bias; introduce dummy variables and interaction terms.', order: 5, estimatedMinutes: 50, tags: ['olympiad', 'multiple-regression', 'omitted-variable-bias', 'dummy-variables'],
    flashcards: [
      { id: 'fc-ol5-l5-1', front: 'What is omitted variable bias and when does it occur?', back: 'Omitted variable bias (OVB) arises when a variable that (i) affects Y and (ii) is correlated with an included regressor X is left out of the model. OLS ascribes the omitted variable\'s effect to X, biasing its coefficient. The bias equals: β̂1_biased = β1_true + β2_true · (Cov(X,Z)/Var(X)), where Z is the omitted variable.', tags: ['olympiad', 'omitted-variable-bias'] },
      { id: 'fc-ol5-l5-2', front: 'What is the purpose of a dummy variable in regression?', back: 'A dummy (binary indicator) variable equals 1 if a unit belongs to a category and 0 otherwise (e.g., female = 1, male = 0). Its coefficient estimates the average difference in Y between the two groups, controlling for other regressors. With k mutually exclusive categories, include k−1 dummies to avoid perfect multicollinearity (the dummy variable trap).', tags: ['olympiad', 'dummy-variables'] },
      { id: 'fc-ol5-l5-3', front: 'What does an interaction term (X1 × X2) in a regression capture?', back: 'An interaction term captures whether the effect of X1 on Y depends on the level of X2. In log(wage) = β0 + β1·female + β2·education + β3·(female × education) + ε, the coefficient β3 measures whether the return to education differs by gender. The marginal effect of education is β2 + β3·female, varying across groups.', tags: ['olympiad', 'interaction-terms'] },
    ],
    quiz: [
      { id: 'q-ol5-l5-1', type: 'mcq', question: 'A study regresses wages on education but omits ability. Ability is positively correlated with both wages and education. The OLS estimate of the education effect will be:', options: ['Upward biased', 'Downward biased', 'Unbiased but inefficient', 'Unbiased and consistent'], correctAnswer: 0, explanation: 'Since ability raises wages (positive effect on Y) and is positively correlated with education (positive correlation with X), the OVB formula gives an upward bias: the education coefficient absorbs part of ability\'s positive effect. This is why naive OLS overstates the returns to schooling.', marks: 2, difficulty: 'olympiad' },
      { id: 'q-ol5-l5-2', type: 'mcq', question: 'A researcher includes dummy variables for all four seasons (spring, summer, autumn, winter) in a regression that also has an intercept. This will cause:', options: ['Perfect multicollinearity (the dummy variable trap)', 'Heteroskedasticity', 'Omitted variable bias', 'Autocorrelation'], correctAnswer: 0, explanation: 'The four season dummies sum to 1 for every observation, which is the same as the intercept column. This perfect linear relationship means (X\'X) is singular and OLS estimates cannot be computed. The remedy is to drop one dummy (the base category) so only three are included.', marks: 2, difficulty: 'olympiad' },
    ],
    content: { isStub: true, conceptualExplanation: `Multiple regression extends the bivariate OLS framework to include several regressors simultaneously: Yi = β0 + β1X1i + β2X2i + … + βkXki + εi. The key interpretive change is that each coefficient now represents the partial effect of one variable on Y, holding all other included regressors constant — the ceteris paribus condition made precise. This is why adding controls can dramatically change a coefficient's magnitude and sign: a bivariate regression of wages on gender may show a large gap, but controlling for occupation, experience, and sector often reduces it substantially. Multiple regression is thus the workhorse for isolating the effect of one variable from confounders.\n\nOmitted variable bias (OVB) is the central failure mode of regression analysis when the goal is causal inference. If a variable Z affects the outcome Y and is correlated with an included regressor X1, then omitting Z pushes its effect into the error term ε. Since E[ε|X1] ≠ 0, the zero conditional mean assumption is violated and OLS is biased. The bias is not random — its direction can be predicted from the signs of the relationship: the bias term is β_Z · (Cov(X1,Z)/Var(X1)). Classic examples include ability bias in returns-to-education regressions and health-selection bias in studies of the economic effects of health insurance. Dummy variables and interaction terms are powerful tools for capturing heterogeneous effects within a regression framework: dummies shift the intercept for subgroups, while interaction terms allow slopes to differ, enabling a model that accommodates, for instance, different returns to education for men and women within a single unified specification.`, prerequisiteRecap: `Hypothesis testing constructed the t-statistic t = (β̂ − β0)/SE(β̂) and established that a 95% confidence interval [β̂ ± 1.96·SE(β̂)] spans the set of null hypotheses we cannot reject at the 5% level; the p-value measures the probability of observing a test statistic at least as extreme as observed under H0, and is not the probability that H0 is true. Multiple regression now extends OLS to multiple regressors, where each coefficient captures the partial effect of one variable holding others constant, and omitted variable bias quantifies how excluding a relevant, correlated regressor distorts those partial effects.`, recallQuestions: [{ id: 'ol5-l5-recall-1', type: 'mcq' as const, question: 'An OLS regression of log(wage) on education gives β̂_educ = 0.08 with SE = 0.02. The t-statistic is 4.0 and the 95% confidence interval is [0.04, 0.12]. A researcher argues this proves that an additional year of education causes a 8% wage increase. What is the most precise econometric critique?', options: ['The OLS estimate identifies an association, not a causal effect; if ability is positively correlated with both education and wages and is omitted from the regression, then E[ε|education] > 0, biasing β̂_educ upward — the true causal return to education may be lower than 8%', 'The t-statistic of 4.0 is too high, suggesting the model is over-fitted and the coefficient is unreliable', 'The confidence interval [0.04, 0.12] is too wide to be informative about the magnitude of the effect', 'Since the p-value is below 5%, the coefficient is causal by the definition of statistical significance'], correctAnswer: 0, explanation: 'Statistical significance (t = 4.0, CI excludes zero) establishes that the association is unlikely due to chance, but does not establish causality. If unobserved ability raises both education and wages, ability is positively correlated with education and enters ε with a positive coefficient. By the OVB formula, β̂_educ is biased upward by β_ability × Cov(education, ability)/Var(education). This is the classic ability bias problem studied by Card (1995) and others, motivating the use of instrumental variables (e.g., proximity to college) to isolate exogenous variation in education.', marks: 1, difficulty: 'olympiad' as const }], realWorldHook: '', vocabulary: [], deeperDive: '', commonMisconceptions: [], examinerTip: '', didYouKnow: '' },
  },
  {
    id: 'ol5-l6', moduleId: 'ol5-econometrics', title: 'Instrumental Variables and Causality', description: 'Explain the endogeneity problem; define valid instruments; introduce 2SLS; discuss famous natural experiments (Card-Krueger minimum wage study).', order: 6, estimatedMinutes: 50, tags: ['olympiad', 'IV', '2SLS', 'natural-experiments', 'endogeneity'],
    flashcards: [
      { id: 'fc-ol5-l6-1', front: 'What are the two conditions a valid instrumental variable must satisfy?', back: '(1) Relevance: the instrument Z must be correlated with the endogenous regressor X — Cov(Z,X) ≠ 0 (testable via first-stage F-statistic; F > 10 is a common rule of thumb). (2) Exclusion restriction: Z must affect Y only through X — Cov(Z,ε) = 0. This second condition is not directly testable and requires economic reasoning.', tags: ['olympiad', 'IV', 'instruments'] },
      { id: 'fc-ol5-l6-2', front: 'Describe the two stages of Two-Stage Least Squares (2SLS).', back: 'Stage 1: Regress the endogenous variable X on the instrument Z (and any other exogenous controls). Save the fitted values X̂. Stage 2: Regress Y on X̂ and the exogenous controls using OLS. The 2SLS estimator β̂IV = Cov(Z,Y)/Cov(Z,X) purges X of its correlation with the error, recovering a consistent estimate of the causal effect.', tags: ['olympiad', '2SLS', 'IV'] },
      { id: 'fc-ol5-l6-3', front: 'How did Card and Krueger (1994) use a natural experiment to study the minimum wage?', back: 'Card-Krueger compared fast-food employment in New Jersey (which raised its minimum wage in 1992) to neighbouring Pennsylvania (which did not). By treating the policy change as an exogenous shock and using difference-in-differences, they found employment did not fall in NJ — challenging the standard competitive prediction. NJ\'s policy change served as a natural instrument: it affected wages (relevant) and was arguably unrelated to NJ-specific employment trends (exclusion).', tags: ['olympiad', 'natural-experiments', 'Card-Krueger'] },
    ],
    quiz: [
      { id: 'q-ol5-l6-1', type: 'mcq', question: 'Card (1995) used proximity to a college as an instrument for years of education to estimate returns to schooling. Which concern would most directly threaten the validity of this instrument?', options: ['People who grow up near colleges have higher-ability parents who also invest more in children\'s human capital', 'The instrument has a weak first-stage F-statistic', 'Omitted variable bias makes education endogenous', 'The instrument is correlated with education'], correctAnswer: 0, explanation: 'The exclusion restriction requires proximity to college affects wages only through education. If proximity correlates with parental ability or community wealth — which independently raise wages — the exclusion restriction is violated. This is the core critique of the instrument, not its relevance (which is easy to verify).', marks: 2, difficulty: 'olympiad' },
      { id: 'q-ol5-l6-2', type: 'mcq', question: 'A weak instrument (low first-stage F-statistic) causes 2SLS to:', options: ['Be biased toward the OLS estimate and have inflated standard errors', 'Perfectly eliminate endogeneity bias', 'Reduce standard errors compared to OLS', 'Improve identification of the causal effect'], correctAnswer: 0, explanation: 'With a weak instrument, the first-stage fitted values X̂ contain little exogenous variation. This causes the 2SLS estimator to collapse toward OLS (which is biased), while amplifying standard errors because little variation is being exploited. The rule of thumb is a first-stage F-statistic above 10.', marks: 2, difficulty: 'olympiad' },
    ],
    content: { isStub: true, conceptualExplanation: `The central challenge of causal inference is endogeneity: the regressor of interest X is correlated with the error term ε, so OLS does not recover the causal effect of X on Y. Endogeneity arises from three main sources: omitted variables (an unobserved confounder drives both X and Y), reverse causality (Y also causes X, as when higher wages attract more educated workers), and measurement error (the recorded value of X differs from its true value, attenuating the OLS coefficient toward zero). Instrumental variables estimation offers a solution: an instrument Z that is correlated with X but affects Y only through X allows us to isolate the exogenous variation in X and use only that variation to identify the causal effect. The IV estimator β̂IV = Cov(Z,Y)/Cov(Z,X) has an elegant interpretation — it scales the reduced-form effect of Z on Y by the first-stage effect of Z on X.\n\nTwo-Stage Least Squares generalises IV to settings with multiple instruments and controls. In the first stage, X is projected onto Z (and other exogenous regressors), producing X̂ — the part of X that is exogenously determined by Z. In the second stage, Y is regressed on X̂, yielding a consistent estimator of the causal parameter. The Card-Krueger (1994) minimum wage study exemplifies the natural experiment approach: by exploiting a policy change in New Jersey that did not occur in neighbouring Pennsylvania, they effectively used geographic variation as an instrument, finding no evidence of employment loss from a minimum wage increase. Their paper sparked the credibility revolution in empirical economics, demonstrating that quasi-experimental variation could overturn long-held theoretical predictions. For olympiad essays, IV is a powerful tool to invoke when discussing why correlational evidence cannot establish causality and how economists attempt to recover causal effects from observational data.`, prerequisiteRecap: `Multiple regression established that the OLS coefficient on X1 in a multivariate model captures the partial effect of X1 on Y holding other regressors constant, and that omitted variable bias follows the formula β̂1_bias = β_Z · Cov(X1,Z)/Var(X1) when a confounding variable Z is excluded; the bias direction is predictable from the signs of Z's effect on Y and its correlation with X1. Instrumental variables estimation resolves this by replacing the endogenous regressor X with its exogenous projection X̂ onto a valid instrument Z, using only the variation in X that is orthogonal to the error term.`, recallQuestions: [{ id: 'ol5-l6-recall-1', type: 'mcq' as const, question: 'A researcher regresses wages on education, omitting ability. Ability has a positive effect on wages (β_ability > 0) and is positively correlated with education (Cov(education, ability) > 0). According to the OVB formula, in which direction is the OLS education coefficient biased, and what type of instrument would be needed to correct this?', options: ['The education coefficient is upward-biased; a valid instrument must be positively correlated with education (relevance) but uncorrelated with ability in the error term (exclusion restriction) — Card (1995) used proximity to college as such an instrument', 'The education coefficient is downward-biased; a valid instrument must be negatively correlated with ability to remove the confounding', 'The direction of bias is indeterminate without knowing the exact magnitude of Cov(education, ability)', 'OLS is unbiased in this setting because ability affects both education and wages symmetrically'], correctAnswer: 0, explanation: 'OVB formula: bias = β_ability × Cov(education, ability)/Var(education). Both β_ability > 0 and Cov(education, ability) > 0, so the bias is positive — OLS overstates the returns to education. A valid IV must satisfy: (1) relevance — Cov(Z, education) ≠ 0, testable via first-stage F-statistic; (2) exclusion — Cov(Z, ability) ≈ 0, requiring economic reasoning. Card (1995) argued that proximity to college raises education access (relevance) but does not directly affect innate ability (exclusion), making it a plausible instrument despite critiques about neighbourhood effects on parental investment.', marks: 1, difficulty: 'olympiad' as const }], realWorldHook: '', vocabulary: [], deeperDive: '', commonMisconceptions: [], examinerTip: '', didYouKnow: '' },
  },
  {
    id: 'ol5-l7', moduleId: 'ol5-econometrics', title: 'Introduction to Panel Data Methods', description: 'Explain fixed effects and random effects models; when to use each; introduce difference-in-differences as a quasi-experimental method.', order: 7, estimatedMinutes: 45, tags: ['olympiad', 'panel-data', 'fixed-effects', 'difference-in-differences'],
    flashcards: [
      { id: 'fc-ol5-l7-1', front: 'What does a fixed effects (FE) model control for, and how?', back: 'A fixed effects model controls for all time-invariant, unobserved unit-level characteristics by including a separate intercept (dummy variable) for each unit. This is equivalent to demeaning — subtracting each unit\'s time-average from all variables. FE eliminates omitted variable bias from stable unobservables (e.g., a country\'s geography, a firm\'s culture) but cannot identify effects of time-invariant regressors.', tags: ['olympiad', 'fixed-effects', 'panel-data'] },
      { id: 'fc-ol5-l7-2', front: 'When should you prefer fixed effects over random effects?', back: 'Use fixed effects when the unobserved individual effect αi is correlated with the regressors — which is usually the case in economic applications and is testable via the Hausman test. Random effects assumes αi is uncorrelated with X (a strong assumption), but is more efficient if valid and can estimate the effects of time-invariant variables. The Hausman test H statistic = (β̂FE − β̂RE)\'[Var(β̂FE) − Var(β̂RE)]⁻¹(β̂FE − β̂RE) tests this.', tags: ['olympiad', 'fixed-effects', 'random-effects'] },
      { id: 'fc-ol5-l7-3', front: 'Explain the difference-in-differences (DiD) estimator.', back: 'DiD compares the change in outcomes for a treated group (pre vs. post treatment) to the change for an untreated control group over the same period. β̂DiD = (Ȳ_treated,post − Ȳ_treated,pre) − (Ȳ_control,post − Ȳ_control,pre). This removes common time trends and unit-level fixed effects, identifying the causal effect of treatment under the parallel trends assumption.', tags: ['olympiad', 'difference-in-differences'] },
    ],
    quiz: [
      { id: 'q-ol5-l7-1', type: 'mcq', question: 'In a panel dataset of 50 countries over 20 years studying the effect of trade openness on growth, a fixed effects estimator is preferred because:', options: ['Country-specific geography, institutions, and culture are correlated with trade openness and growth', 'It produces smaller standard errors than OLS', 'It can identify the effect of time-invariant country characteristics', 'The Hausman test always favours fixed effects'], correctAnswer: 0, explanation: 'Fixed effects eliminate bias from time-invariant confounders — geography, colonial history, institutional quality — that plausibly correlate with both trade openness and growth. This is the canonical motivation: the unobserved country effect αi is almost certainly correlated with trade policy, violating the random effects assumption.', marks: 2, difficulty: 'olympiad' },
      { id: 'q-ol5-l7-2', type: 'mcq', question: 'The key identifying assumption of a difference-in-differences estimator is:', options: ['Parallel trends: absent treatment, treated and control groups would have followed the same trajectory', 'Random assignment of treatment to groups', 'No spillover effects from control to treated units', 'The instrument satisfies the exclusion restriction'], correctAnswer: 0, explanation: 'Parallel trends is the core DiD assumption: that the control group provides a valid counterfactual for what would have happened to the treated group absent the policy. It cannot be directly tested post-treatment, but is often supported by showing pre-treatment trends were parallel — a key robustness check in applied work.', marks: 2, difficulty: 'olympiad' },
    ],
    content: { isStub: true, conceptualExplanation: `Panel data methods exploit the longitudinal dimension of data — repeated observations on the same units — to control for unobserved heterogeneity that would confound cross-sectional comparisons. The fixed effects model writes Yi,t = αi + β'Xi,t + εi,t, where αi is a unit-specific intercept that absorbs all stable, unobserved characteristics of unit i (a country's institutions, a firm's management quality, a worker's innate ability). Since αi is estimated rather than modelled, it makes no assumptions about its relationship with Xi,t, rendering FE robust to correlation between unobservables and regressors. The trade-off is that FE cannot identify the effect of any variable that does not vary over time within a unit — if you want to estimate the effect of a country's colonial history on current income using FE, you cannot, because colonial history is fixed.\n\nDifference-in-differences (DiD) is the most widely used quasi-experimental method in applied economics. The intuition is simple: compare the change in outcomes for units that received a treatment (policy, natural disaster, market shock) to the change for untreated units over the same period. The first difference removes pre-existing level differences between groups; the second difference removes common time trends affecting both groups. The resulting β̂DiD estimates the average treatment effect on the treated (ATT) under the parallel trends assumption — that, absent the treatment, both groups would have evolved similarly. DiD has been used to study the effects of minimum wage laws (Card-Krueger), job training programs, immigration shocks, and health insurance expansions. Recent methodological advances (staggered DiD, Sun-Abraham estimators) address complications when treatment timing varies across units, which olympiad contestants at the IEO level may encounter in research-oriented problems.`, prerequisiteRecap: `Instrumental variables estimation recovers a causal effect by decomposing the endogenous regressor into an exogenous component X̂ (projected onto the instrument Z) and a residual correlated with the error; the 2SLS estimator β̂IV = Cov(Z,Y)/Cov(Z,X) is consistent when Z satisfies relevance (Cov(Z,X) ≠ 0, verified by first-stage F > 10) and the exclusion restriction (Cov(Z,ε) = 0). Panel data and difference-in-differences methods provide an alternative identification strategy that uses within-unit variation over time to remove time-invariant confounders, circumventing endogeneity without requiring an external instrument.`, recallQuestions: [{ id: 'ol5-l7-recall-1', type: 'mcq' as const, question: 'Card and Krueger (1994) used New Jersey\'s minimum wage increase as a natural experiment, comparing fast-food employment in NJ to Pennsylvania (DiD design). The key identifying assumption is parallel trends. Which empirical test most directly assesses the plausibility of this assumption?', options: ['Examining pre-treatment trends: if NJ and PA had parallel employment trends in fast-food sectors in the periods before the minimum wage change, this supports (but does not prove) the counterfactual parallel trends assumption required for DiD validity', 'Testing whether NJ and PA have similar average employment levels in the post-treatment period', 'Running a Hausman test comparing fixed effects to random effects estimates', 'Checking that the instrument (NJ policy) satisfies the exclusion restriction by regressing wages on NJ status controlling for employment'], correctAnswer: 0, explanation: 'The parallel trends assumption — that absent the minimum wage increase, NJ and PA employment would have followed the same trajectory — cannot be directly tested post-treatment (we never observe the counterfactual NJ outcome). The best available evidence is whether pre-treatment trends were parallel: if NJ and PA moved together before the policy change, it is more plausible they would have continued to do so absent the treatment. Formally, researchers add leads (future treatment indicators) to the DiD specification and test that they are jointly insignificant — a procedure known as an "event study" or "pre-trends test."', marks: 1, difficulty: 'olympiad' as const }], realWorldHook: '', vocabulary: [], deeperDive: '', commonMisconceptions: [], examinerTip: '', didYouKnow: '' },
  },
]

